/// <summary>
/// Controller class for the import log process of the Unsold Journal in the ETGSPAIN model.
/// This controller handles the execution of the service and the interaction with the calling form.
/// </summary>
class ETGSPAINUnsoldJournalImportLogController extends SysOperationServiceController
{
}

Method.Source:
/// <summary>
/// Method to instantiate a new instance of the class. It sets the service and method to be executed synchronously.
/// </summary>
public void new()
{
    super(classStr(ETGSPAINUnsoldJournalImportLogService),
        methodStr(ETGSPAINUnsoldJournalImportLogService, processOperation),
        SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// Method <c>defaultCaption</c> to return the description of the process that will be shown to the user.
/// </summary>
/// <returns>Returns the process description from a label resource.</returns>
public ClassDescription defaultCaption()
{
    return "@ETGSPAINLabels:InventJournalLineImport";
}

/// <summary>
/// Main method, invoked from a MenuItem to start the service.
/// It configures the arguments and contract for the process and initiates the operation.
/// </summary>
/// <param name="_args">The arguments passed to the controller.</param>
public static void main(Args _args)
{
    ETGSPAINUnsoldJournalImportLogController    controller;
    ETGSPAINUnsoldJournalImportLogContract      contract;
    ETGSPAINUnsoldJournalTable                  etgspainUnsoldJournalTable = _args.record();

    controller = new ETGSPAINUnsoldJournalImportLogController();
    controller.parmArgs(_args);
    controller.parmLoadFromSysLastValue(false);
    controller.showBatchTab(false);

    contract = controller.getDataContractObject('_contract');
    contract.parmETGSPAINUnsoldJournalId(etgspainUnsoldJournalTable.JournalId);

    controller.startOperation();

    controller.refreshCallingForm(_args);
}

/// <summary>
/// Refreshes the form from which the process was called. This ensures that the form is updated with the latest data after the process execution.
/// </summary>
/// <param name="_args">The arguments containing the calling form data.</param>
private void refreshCallingForm(Args _args)
{

    FormDataSource formDataSource;

    if(_args && _args.record() && _args.record().isFormDataSource())
    {
        formDataSource = _args.record().dataSource();
        formDataSource.research(true);
    }
}
